const input = $input.first().json;
const query = input.query;
if (!query) return [{ json: { error: 'Parameter "query" is required (country name or ISO code).' } }];

const fields = 'name,capital,population,area,region,subregion,languages,currencies,timezones,flag,cca2,cca3,borders';
let countries;

try {
  // Try by name first
  countries = await helpers.httpRequest({
    method: 'GET',
    url: 'https://restcountries.com/v3.1/name/' + encodeURIComponent(query) + '?fields=' + fields
  });
} catch (e1) {
  try {
    // Fallback: try as ISO code
    countries = await helpers.httpRequest({
      method: 'GET',
      url: 'https://restcountries.com/v3.1/alpha/' + encodeURIComponent(query) + '?fields=' + fields
    });
    // alpha endpoint returns object, not array
    if (!Array.isArray(countries)) countries = [countries];
  } catch (e2) {
    return [{ json: { error: 'Country not found: "' + query + '". Try a country name (e.g. Germany) or ISO code (e.g. DE).' } }];
  }
}

if (!Array.isArray(countries)) countries = [countries];
if (countries.length === 0) {
  return [{ json: { error: 'No results for "' + query + '".' } }];
}

let result = '';
for (const c of countries.slice(0, 3)) {
  const name = c.name ? (c.name.common || c.name.official || query) : query;
  const official = c.name ? c.name.official : '';
  const capital = Array.isArray(c.capital) ? c.capital.join(', ') : (c.capital || 'N/A');
  const pop = c.population ? c.population.toLocaleString('en-US') : 'N/A';
  const area = c.area ? c.area.toLocaleString('en-US') + ' km²' : 'N/A';
  const region = [c.region, c.subregion].filter(Boolean).join(' / ');
  const langs = c.languages ? Object.values(c.languages).join(', ') : 'N/A';
  const currs = c.currencies ? Object.entries(c.currencies).map(([code, info]) => info.name + ' (' + code + ', ' + (info.symbol || '') + ')').join(', ') : 'N/A';
  const tz = Array.isArray(c.timezones) ? c.timezones.join(', ') : 'N/A';
  const codes = [c.cca2, c.cca3].filter(Boolean).join(' / ');
  const flag = c.flag || '';

  result += flag + ' ' + name;
  if (official && official !== name) result += ' (' + official + ')';
  result += '\n';
  result += '  Codes: ' + codes + '\n';
  result += '  Capital: ' + capital + '\n';
  result += '  Population: ' + pop + '\n';
  result += '  Area: ' + area + '\n';
  result += '  Region: ' + region + '\n';
  result += '  Languages: ' + langs + '\n';
  result += '  Currencies: ' + currs + '\n';
  result += '  Timezones: ' + tz + '\n';
  if (c.borders && c.borders.length > 0) {
    result += '  Borders: ' + c.borders.join(', ') + '\n';
  }
  result += '\n';
}

if (countries.length > 3) {
  result += '(' + (countries.length - 3) + ' more results omitted)';
}

return [{ json: { result: result.trim() } }];
